import{_ as t,o,c as l,a8 as a}from"./chunks/framework.DvHWw5tv.js";const h=JSON.parse('{"title":"useScrollComputed","description":"","frontmatter":{},"headers":[],"relativePath":"en/design/hooks/useScroll.md","filePath":"en/design/hooks/useScroll.md"}'),r={name:"en/design/hooks/useScroll.md"};function n(s,e,i,c,d,u){return o(),l("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1776104037000"},[...e[0]||(e[0]=[a('<h1 id="usescrollcomputed" tabindex="-1">useScrollComputed <a class="header-anchor" href="#usescrollcomputed" aria-label="Permalink to “useScrollComputed”">​</a></h1><h3 id="usescrollcomputed-unified-scrollbar-style-management-hooks" tabindex="-1">useScrollComputed: Unified Scrollbar Style Management Hooks <a class="header-anchor" href="#usescrollcomputed-unified-scrollbar-style-management-hooks" aria-label="Permalink to “useScrollComputed: Unified Scrollbar Style Management Hooks”">​</a></h3><h2 id="pain-points" tabindex="-1">Pain Points <a class="header-anchor" href="#pain-points" aria-label="Permalink to “Pain Points”">​</a></h2><p>Native browser scrollbar styles vary widely, are difficult to unify, and modern UI designs often require custom appearances (colors, width, hover effects). Common issues include:</p><ul><li>Global scrollbar styles cannot be directly controlled via ordinary CSS variables (must be applied to <code>:root</code>)</li><li>Different components (Scrollbar, Virtual List, overflowing containers) have repetitive scrollbar styling needs</li><li>Dynamic theme switching requires real-time scrollbar color updates and cleanup on component destruction</li><li>Coexistence of local and global scrollbar requirements (global affects entire page, local only affects container)</li><li>Inconsistent handling of width/height units, often missing <code>px</code> conversion</li><li>Uncleaned global styles lead to residue or pollution during multi-instance or switching scenarios</li></ul><p>If each scroll-related component handles this logic independently, it results in style inconsistency, missed cleanup, and difficult theme adaptation.</p><h2 id="design-goals" tabindex="-1">Design Goals <a class="header-anchor" href="#design-goals" aria-label="Permalink to “Design Goals”">​</a></h2><p>This file provides two complementary scrollbar style management solutions:</p><ul><li><code>useScrollStyles</code>: <strong>Global scrollbar style control</strong>, dynamically injected into <code>:root</code> with automatic cleanup</li><li><code>useScrollVariables</code>: <strong>Local scrollbar style control</strong>, returns a CSS variables object suitable for individual containers</li></ul><p>The common goal is to <strong>unify scrollbar visual specifications, support both global and local modes, and perfectly adapt to dynamic themes and component lifecycles</strong>.</p><h2 id="core-utility-comparison" tabindex="-1">Core Utility Comparison <a class="header-anchor" href="#core-utility-comparison" aria-label="Permalink to “Core Utility Comparison”">​</a></h2><table tabindex="0"><thead><tr><th>Hook</th><th>Applicable Scenario</th><th>Scope</th><th>Key Features</th></tr></thead><tbody><tr><td><strong>useScrollStyles</strong></td><td>Affecting entire page scrollbar (e.g., global theme)</td><td>Global <code>:root</code></td><td>Automatically injects/cleans global variables<br>Reactive <code>ComputedRef</code><br>Lifecycle safe</td></tr><tr><td><strong>useScrollVariables</strong></td><td>Custom Scrollbar container or local overflow area</td><td>Local container</td><td>Returns plain object, no side effects<br>Auto unit handling<br>Variable name prefix isolation</td></tr></tbody></table><h2 id="core-features" tabindex="-1">Core Features <a class="header-anchor" href="#core-features" aria-label="Permalink to “Core Features”">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td><strong>Automatic Lifecycle Management for Global Styles</strong></td><td>Injects <code>:root</code> variables on <code>onMounted</code>, automatically removes on <code>onUnmounted</code>, preventing style leaks</td></tr><tr><td><strong>Reactive Local Styles</strong></td><td><code>useScrollStyles</code> returns <code>ComputedRef&lt;CSSProperties&gt;</code>, supporting real-time updates with prop changes</td></tr><tr><td><strong>Intelligent Unit Handling</strong></td><td><code>scrollWidth</code>/<code>scrollHeight</code> numbers auto-appended with <code>px</code>, strings passed through as-is</td></tr><tr><td><strong>Variable Name Isolation</strong></td><td>Local variables use <code>--scrollbar-container-*</code> prefix to avoid conflicts with global ones</td></tr><tr><td><strong>Unified Global Variables</strong></td><td>Uses <code>--global-scroll-*</code> series to ensure consistent scrollbar visuals across the entire library</td></tr><tr><td><strong>SSR Safe</strong></td><td>DOM operations only execute on client side (implicitly via <code>onMounted</code>/<code>onUnmounted</code>)</td></tr></tbody></table><h2 id="design-value" tabindex="-1">Design Value <a class="header-anchor" href="#design-value" aria-label="Permalink to “Design Value”">​</a></h2><p>These two tools together form a complete scrollbar style solution for the component library:</p><ul><li><strong>Global consistency</strong>: <code>useScrollStyles</code> ensures all native scrollbars update synchronously during theme changes</li><li><strong>Local flexibility</strong>: <code>useScrollVariables</code> supports independent custom appearance for individual containers</li><li><strong>Safe and reliable</strong>: Automatic cleanup mechanisms prevent style pollution, ideal for dynamically loaded components</li><li><strong>Seamless theme integration</strong>: Standardized variable names and unified color props</li><li><strong>Reduced repetition</strong>: All scrollbar-related style logic is centralized here; components need not worry about implementation details</li></ul>',17)])])}const m=t(r,[["render",n]]);export{h as __pageData,m as default};
